const targets = [
  {
    company: 'Capgemini',
    url: 'https://www.capgemini.com/jobs/search/?search_term=customer+success+operations+project+coordinator&location=india&radius=50',
    api_url: 'https://www.capgemini.com/api/jobs?q=customer%20success%20operations&location=India'
  },
  {
    company: 'Accenture',
    url: 'https://www.accenture.com/in-en/careers/jobsearch?jkw=customer+success+operations+project+coordinator&jl=India&jepf=Regular'
  },
  {
    company: 'JLL',
    url: 'https://careers.jll.com/en/jobs?search=customer+success+operations&location=India'
  },
  {
    company: 'CBRE',
    url: 'https://careers.cbre.com/en_US/careers/SearchJobs/customer%20success%20operations?3_100_3=161512&3_100_3=161477'
  },
  {
    company: 'EY',
    url: 'https://careers.ey.com/ey/search/#q=customer%20success%20operations%20project%20coordinator&t=Jobs&locationsearch=India'
  }
];

return targets.map(t => ({ json: { ...t, source_platform: 'tier1' } }));

const html = typeof $input.first().json === 'string' ? $input.first().json : JSON.stringify($input.first().json);
const prev = $('Build Tier1 Targets').first().json;

const keywords = ['customer success', 'operations', 'coordinator', 'project', 'business development', 'client', 'account manager'];

// Extract job links from page
const linkMatches = html.match(/href="([^"]*job[^"]*|[^"]*career[^"]*|[^"]*position[^"]*)"/gi) || [];
const jobs = [];
const seenUrls = new Set();

for (const link of linkMatches) {
  const urlMatch = link.match(/href="([^"]+)"/);
  if (!urlMatch) continue;
  let url = urlMatch[1];
  if (!url.startsWith('http')) {
    const base = new URL(prev.url);
    url = `${base.protocol}//${base.host}${url.startsWith('/') ? '' : '/'}${url}`;
  }
  if (seenUrls.has(url)) continue;
  seenUrls.add(url);

  // Check if surrounding text contains relevant keywords
  const urlLower = url.toLowerCase();
  const hasKeyword = keywords.some(k => urlLower.includes(k.replace(/ /g, '-')) || urlLower.includes(k.replace(/ /g, '_')));

  if (hasKeyword || url.includes('/job/') || url.includes('/jobs/') || url.includes('/position/')) {
    jobs.push({
      job_url: url,
      company: prev.company,
      source_platform: 'tier1_' + prev.company.toLowerCase(),
      job_title: url.split('/').pop().replace(/-/g, ' ').replace(/_/g, ' ') || 'See listing',
      location: 'India',
      description: `${prev.company} job posting. Review at: ${url}`
    });
  }
}

// Limit to 10 per company to avoid flooding
return jobs.slice(0, 10).map(j => ({ json: j }));

const seen = $getWorkflowStaticData('global');
if (!seen.tier1SeenUrls) seen.tier1SeenUrls = [];

const item = $input.first().json;
if (seen.tier1SeenUrls.includes(item.job_url)) return [];

seen.tier1SeenUrls.push(item.job_url);
if (seen.tier1SeenUrls.length > 2000) seen.tier1SeenUrls = seen.tier1SeenUrls.slice(-1000);

return [{ json: item }];
